+/// Escape special LIKE pattern characters (%, _, \) for literal matching.
+///
+/// Use with `LIKE ? ESCAPE '\\'` in SQL queries.
+fn escape_like_pattern(s: &str) -> String {
+    s.replace('\\', "\\\\")
+        .replace('%', "\\%")
+        .replace('_', "\\_")
